Sledite izvajanju naslednjega programa in ugotovite, kaj ta program izpiše. 
Pascal: 
var x,y : integer; 
begin 
  x:=22; y:=10; 
  while (x<50) or (y mod 2 =1) do 
  begin 
    x:=x+ (y div 2); 
    y:=x + (y div 3); 
    if ((y+x) div 2)<20 then  
      y:=y+10; 
    writeln(x,' ',y); 
  end; 
end. 
C: 
#include <stdio.h> 
void main() 
{ 
  int x=22,y=10; 
  while ((x<50) || (y%2==1)) { 
    x=x+(y/2); 
    y=x+(y/3); 
    if ((x+y)/2<20) 
      y=y+10; 
    printf("%d %d \n",x,y); 
  } 
}
